function renderBlog() {
  var cat = getParam('category') || '';
  var container = document.getElementById('blogContainer');
  var featured = document.getElementById('blogFeatured');
  if (!container) return;

  var html = '';
  for (var i = 0; i < BLOG_POSTS.length; i++) {
    var p = BLOG_POSTS[i];
    if (cat && p.category !== cat) continue;
    var catColors = { News: '#e53935', Features: '#1e88e5', Guides: '#43a047', Gear: '#8e24aa' };
    var color = catColors[p.category] || '#757575';
    html += '<article class="blog-card" data-aos="fade-up">';
    html += '<a href="blog/' + p.id + '.html"><img class="blog-card-img" src="' + p.image + '" alt="' + esc(p.title) + '" loading="lazy" width="600" height="300"></a>';
    html += '<div class="blog-card-body">';
    html += '<span class="blog-category" style="background:' + color + '">' + esc(p.category) + '</span>';
    html += '<h2 class="blog-title"><a href="blog/' + p.id + '.html">' + esc(p.title) + '</a></h2>';
    html += '<div class="blog-meta">' + esc(p.date) + '</div>';
    html += '<p class="blog-excerpt">' + esc(p.excerpt) + '</p>';
    html += '<a href="blog/' + p.id + '.html" class="blog-read-more">Read more <i class="fas fa-arrow-right"></i></a>';
    html += '</div></article>';
  }
  container.innerHTML = html || '<p style="text-align:center;color:var(--text-muted);padding:40px 0">No articles found in this category.</p>';

  if (featured && !cat && BLOG_POSTS.length > 0) {
    var f = BLOG_POSTS[0];
    var catColors = { News: '#e53935', Features: '#1e88e5', Guides: '#43a047', Gear: '#8e24aa' };
    var color = catColors[f.category] || '#757575';
    featured.style.display = 'block';
    featured.innerHTML =
      '<article class="blog-card" style="background:var(--primary-dark);color:#fff">' +
      '<div class="blog-card-body" style="text-align:center;padding:32px">' +
      '<span class="blog-category" style="background:' + color + '">' + esc(f.category) + '</span>' +
      '<h2 class="blog-title" style="font-size:22px;margin:10px 0"><a href="blog/' + f.id + '.html" style="color:#fff;text-decoration:none">' + esc(f.title) + '</a></h2>' +
      '<div class="blog-meta" style="color:rgba(255,255,255,0.7)">' + esc(f.date) + '</div>' +
      '<p style="color:rgba(255,255,255,0.85);font-size:14px;line-height:1.7;margin-bottom:14px">' + esc(f.excerpt) + '</p>' +
      '<a href="blog/' + f.id + '.html" class="blog-read-more" style="color:#fff;font-weight:600">Read more <i class="fas fa-arrow-right"></i></a>' +
      '</div></article>';
  } else if (featured) {
    featured.style.display = 'none';
  }

  function getParam(name) {
    var url = window.location.search.substring(1);
    var params = url.split('&');
    for (var j = 0; j < params.length; j++) {
      var p = params[j].split('=');
      if (p[0] === name) return decodeURIComponent(p[1] || '');
    }
    return '';
  }

  function esc(s) {
    if (!s) return '';
    return s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
  }
}